using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class CalculatorTests
{
    [TestMethod]
    public void Add_TwoNumbers_ReturnsSum()
    {
        // Arrange & Act
        var result = 2 + 3;

        // Assert
        Assert.AreEqual(5, result);
    }

    [TestMethod]
    [DataRow(0, 0, 0)]
    [DataRow(-1, 1, 0)]
    [DataRow(10, 20, 30)]
    public void Add_DataDriven_ReturnsExpectedSum(int a, int b, int expected)
    {
        Assert.AreEqual(expected, a + b);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
[DoNotParallelize]
public sealed class DatabaseIntegrationTests
{
    [TestMethod]
    public void CreateRecord_InsertsSuccessfully()
    {
        // These tests run sequentially — safe for shared DB state
        Assert.IsTrue(true);
    }

    [TestMethod]
    public void DeleteRecord_AfterCreate_RemovesRecord()
    {
        Assert.IsTrue(true);
    }
}

